mapper.select:
select p.id, p.name, p.`condition`, p.details, p.images, p.clicks, p.sid, p.originalprice, p.currentprice, p.deal, p.address, p.status, s.name sname, ifnull(r.pid,0) pid from product p left join recommend r on p.id=r.pid left join sc s on p.sid=s.id where 1=1
and p.name like concat('%','${name}','%')
and p.sid=#{sid}
and p.deal=#{deal}
and p.status=#{status}

select p.id, p.name, p.`condition`, p.details, p.images, p.originalprice, p.clicks, p.currentprice, p.deal, p.address, p.comments, s.name sname, ifnull(r.pid,0) pid from product p left join recommend r on p.id=r.pid left join sc s on p.sid=s.id where p.comments!=0
and p.name like concat('%','${name}','%')
and p.sid=#{sid}
and p.deal=#{deal}
and p.status=#{status}
